SELECT total_users, peak_hour
FROM lab_usage
WHERE lab_id = 1 AND usage_date = '2023-10-01';

SELECT lab_name
FROM labs
WHERE laser_printing = 1;

SELECT lab_name, capacity
FROM labs
ORDER BY capacity DESC;

SELECT COUNT(*) AS pending_feedback_count
  FROM lab_feedback
  WHERE lab_id = 0 AND status = 'pending';

SELECT COUNT(*) 
  FROM labs 
  WHERE laser_printing = 1;

SELECT lab_name, location, capacity
FROM labs
ORDER BY capacity DESC;

SELECT AVG(average_duration) AS average_visit_duration
FROM lab_usage
WHERE usage_date = '2023-10-02' AND total_users > 10;

SELECT lab_name, capacity
FROM labs
WHERE capacity = (SELECT MAX(capacity) FROM labs);

SELECT total_users
FROM lab_usage
WHERE lab_id = 1 AND usage_date = '2023-10-02';
